(1, 'service', 'Dịch vụ thành lập doanh nghiệp FDI', 'FDI Company Establishment Service', 'FDI会社設立サービス', 'Hỗ trợ tư vấn và thành lập doanh nghiệp FDI tại Việt Nam', 'Consulting and establishment support for FDI companies in Vietnam', 'ベトナムにおけるFDI会社設立支援', '<div><h1>Nội dung tiếng Việt</h1></div>', '<div><h1>English Content</h1></div>', '<div><h1>日本語コンテンツ</h1></div>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=100&q=80&auto=format&fit=crop', 120, 'published', '2026-05-19', 'dich-vu-thanh-lap-doanh-nghiep-fdi', '2026-05-19 15:10:08', '2026-05-19 15:10:08'),
(24, 'home', 'Về LE VIET NAM', '', '', 'LE VIET NAM tự hào là đơn vị tư vấn chiến lược hàng đầu, chuyên cung cấp các giải pháp toàn diện về tư vấn xúc tiến đầu tư và hỗ trợ thành lập doanh nghiệp trong nước cũng như quốc tế (FDI).\n\nVới đội ngũ chuyên gia giàu kinh nghiệm, chúng tôi cam kết đồng hành cùng doanh nghiệp từ những bước đầu tiên, giải quyết mọi thủ tục pháp lý phức tạp và nâng cao năng lực nhân sự, giúp doanh nghiệp phát triển bền vững tại thị trường Việt Nam.', '', '', '<div class=\"bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-200\"><div class=\"p-8 md:p-10 text-gray-900 space-y-6\"><h2 class=\"text-2xl font-bold text-orange-600 mb-4 border-b pb-2\">Câu Chuyện Của Chúng Tôi</h2><p class=\"leading-relaxed\"><strong>LE VIET NAM</strong> được thành lập với tâm huyết trở thành cầu nối vững chắc, đưa các nhà đầu tư quốc tế đến với thị trường Việt Nam đầy tiềm năng, đồng thời hỗ trợ các doanh nghiệp trong nước xây dựng nền móng pháp lý vững chắc.</p><p class=\"leading-relaxed\">Chúng tôi hiểu rằng, rào cản về thủ tục hành chính, pháp lý và sự khác biệt văn hóa luôn là những thách thức lớn đối với doanh nghiệp. Với đội ngũ chuyên gia, luật sư và cố vấn giàu kinh nghiệm, LE VIET NAM cam kết mang đến những giải pháp tư vấn toàn diện, chính xác và hiệu quả nhất.</p><div class=\"grid md:grid-cols-2 gap-8 mt-8\"><div class=\"bg-slate-50 p-6 rounded-xl border border-gray-100\"><h3 class=\"text-xl font-bold text-[#1e1b4b] mb-3 flex items-center gap-2\"><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-globe text-orange-500\" aria-hidden=\"true\"><circle cx=\"12\" cy=\"12\" r=\"10\"></circle><path d=\"M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20\"></path><path d=\"M2 12h20\"></path></svg> Tầm Nhìn</h3><p class=\"text-gray-700\">Trở thành đơn vị tư vấn chiến lược và cung cấp dịch vụ pháp lý hàng đầu tại Việt Nam, là điểm đến đầu tiên mà các nhà đầu tư quốc tế nghĩ tới khi quyết định thâm nhập thị trường Việt Nam.</p></div><div class=\"bg-slate-50 p-6 rounded-xl border border-gray-100\"><h3 class=\"text-xl font-bold text-[#1e1b4b] mb-3 flex items-center gap-2\"><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-circle-check-big text-orange-500\" aria-hidden=\"true\"><path d=\"M21.801 10A10 10 0 1 1 17 3.335\"></path><path d=\"m9 11 3 3L22 4\"></path></svg> Sứ Mệnh</h3><p class=\"text-gray-700\">Đơn giản hóa mọi thủ tục pháp lý phức tạp, tối ưu hóa thời gian và chi phí cho khách hàng. Nâng tầm năng lực nhân sự Việt thông qua các chương trình đào tạo chuẩn quốc tế.</p></div></div><h2 class=\"text-2xl font-bold text-orange-600 mb-4 border-b pb-2 mt-10\">Giá Trị Cốt Lõi</h2><div class=\"grid grid-cols-1 sm:grid-cols-3 gap-6\"><div class=\"text-center p-4\"><div class=\"bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-orange-600 font-bold text-xl\">01</div><h4 class=\"font-bold text-indigo-900 mb-2\">Chuyên Nghiệp</h4><p class=\"text-sm text-gray-600\">Am hiểu luật pháp, xử lý hồ sơ nhanh chóng, chính xác.</p></div><div class=\"text-center p-4\"><div class=\"bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-orange-600 font-bold text-xl\">02</div><h4 class=\"font-bold text-indigo-900 mb-2\">Tận Tâm</h4><p class=\"text-sm text-gray-600\">Luôn đặt lợi ích của khách hàng lên hàng đầu, đồng hành trọn đời.</p></div><div class=\"text-center p-4\"><div class=\"bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-orange-600 font-bold text-xl\">03</div><h4 class=\"font-bold text-indigo-900 mb-2\">Bảo Mật</h4><p class=\"text-sm text-gray-600\">Cam kết bảo mật tuyệt đối mọi thông tin của doanh nghiệp và đối tác.</p></div></div></div></div>\n', '', '', '/uploads/1779464125563.jpg', 0, 'published', '2026-05-22', 've-le-viet-nam', '2026-05-22 15:35:25', '2026-05-23 09:48:50'),
(39, 'service', 'Hỗ Trợ Tư Vấn Xúc Tiến Đầu Tư & Thành Lập FDI', '', '', 'Kêu gọi và giới thiệu về môi trường đầu tư kinh doanh tại Việt Nam với các cá nhân, tổ chức kinh tế và các doanh nghiệp nước ngoài nhằm thu hút đầu tư nước ngoài vào Việt Nam.', '', '', '<div class=\"space-y-10\">\n            <div class=\"bg-[#0f3762] text-white rounded-t-[24px] p-6 flex items-center gap-4 shadow-xl\">\n              <div class=\"w-12 h-12 bg-white/10 rounded-full flex items-center justify-center text-brand-orange\">\n                <i class=\"fa-solid fa-earth-asia text-2xl animate-spin-slow\"></i>\n              </div>\n              <h1 class=\"text-xl md:text-2xl font-extrabold tracking-tight\">\n                Hỗ Trợ Tư Vấn Xúc Tiến Đầu Tư & Thành Lập FDI\n              </h1>\n            </div>\n\n            <section class=\"bg-white rounded-b-[24px] p-8 md:p-10 shadow-xl text-slate-800 -mt-10 space-y-10\">\n              \n              <!-- Hộp Kêu Gọi & Giới Thiệu (Nền xanh nhạt, chữ xanh đậm) -->\n              <div class=\"bg-[#f0f4ff] border-l-4 border-indigo-600 text-indigo-950 p-6 rounded-r-2xl text-[14.5px] leading-relaxed font-medium\">\n                Kêu gọi và giới thiệu về môi trường đầu tư kinh doanh tại Việt Nam với các cá nhân, tổ chức kinh tế và các doanh nghiệp nước ngoài nhằm thu hút đầu tư nước ngoài vào Việt Nam.\n              </div>\n\n              <!-- Phần I: Tư vấn chủ trương và chính sách đầu tư (HTML Chay) -->\n              <div class=\"space-y-6\">\n                <h3 class=\"text-[17px] font-extrabold text-brand-orange border-b border-slate-100 pb-3 uppercase tracking-wide\">\n                  I. Tư vấn chủ trương và chính sách đầu tư\n                </h3>\n                <ul class=\"space-y-4\">\n                  <li class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-brand-orange text-base mt-1 flex-shrink-0\"></i>\n                    <span>Tư vấn các chủ trương, chính sách đầu tư theo quy định của pháp luật Việt Nam liên quan đến lĩnh vực đầu tư của nhà đầu tư.</span>\n                  </li>\n                  <li class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-brand-orange text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ nghiên cứu tính khả thi về mặt pháp lý của Dự án đầu tư tại Việt Nam.</span>\n                  </li>\n                  <li class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-brand-orange text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ nghiên cứu các điều kiện pháp lý áp dụng cho dự án đầu tư trong từng trường hợp cụ thể.</span>\n                  </li>\n                  <li class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-brand-orange text-base mt-1 flex-shrink-0\"></i>\n                    <span>Thẩm tra năng lực pháp lý của các đối tác tham gia đầu tư trong các dự án.</span>\n                  </li>\n                  <li class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-brand-orange text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ nghiên cứu các ưu đãi đầu tư được áp dụng đối với dự án.</span>\n                  </li>\n                  <li class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-brand-orange text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ chuẩn bị các công việc cần thiết để nhà đầu tư có thể chính thức thực hiện công việc kinh doanh.</span>\n                  </li>\n                </ul>\n              </div>\n\n              <!-- Phần II: Hỗ trợ thành lập công ty 100% vốn đầu tư nước ngoài (HTML Chay) -->\n              <div class=\"space-y-6\">\n                <h3 class=\"text-[17px] font-extrabold text-brand-orange border-b border-slate-100 pb-3 uppercase tracking-wide\">\n                  II. Hỗ trợ thành lập công ty 100% vốn đầu tư nước ngoài\n                </h3>\n                \n                <p class=\"text-slate-500 text-[13.5px] leading-relaxed text-justify\">\n                  Nhằm hỗ trợ các nhà đầu tư nắm bắt được các quy định đầu tư, kinh doanh theo đúng Pháp luật tại Việt Nam và giải quyết nhanh chóng, chính xác các thủ tục hành chính liên quan tới việc xin giấy phép đầu tư và thành lập công ty 100% vốn nước ngoài tại Việt Nam, chúng tôi cung cấp dịch vụ trọn gói bao gồm:\n                </p>\n\n                <!-- Box danh sách chi tiết HTML Chay (Viền mỏng, bo tròn mềm mại) -->\n                <div class=\"bg-white border border-slate-100 rounded-2xl p-6 shadow-sm space-y-4\">\n                  <div class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-indigo-600 text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ, tư vấn điều kiện về ngành nghề đối với doanh nghiệp nước ngoài/có vốn đầu tư nước ngoài khi thành lập doanh nghiệp tại Việt Nam;</span>\n                  </div>\n                  <div class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-indigo-600 text-base mt-1 flex-shrink-0\"></i>\n                    <span>Tư vấn lựa chọn loại hình công ty phù hợp cho nhà đầu tư: Công ty TNHH hay Công ty cổ phần;</span>\n                  </div>\n                  <div class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-indigo-600 text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ, tư vấn các điều kiện về đăng ký địa điểm thực hiện dự án, địa chỉ trụ sở, vốn, ngành nghề kinh doanh, mở tài khoản chuyển vốn, thời hạn góp vốn;</span>\n                  </div>\n                  <div class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-indigo-600 text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ, tư vấn điều kiện, hướng dẫn nhà đầu tư chuẩn bị tài liệu, hồ sơ tại Việt Nam cần thiết để thành lập công ty có vốn đầu tư nước ngoài;</span>\n                  </div>\n                  <div class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-indigo-600 text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ, tư vấn, soạn thảo hồ sơ thành lập công ty cho nhà đầu tư;</span>\n                  </div>\n                  <div class=\"flex items-start gap-3.5 text-slate-600 text-[14px] leading-relaxed\">\n                    <i class=\"fa-regular fa-circle-check text-indigo-600 text-base mt-1 flex-shrink-0\"></i>\n                    <span>Hỗ trợ, đại diện nhà đầu tư làm việc với các cơ quan nhà nước có thẩm quyền của Việt Nam trong quá trình thực hiện thủ tục thành lập công ty cho nhà đầu tư.</span>\n                  </div>\n                </div>\n              </div>\n\n              <!-- Khung Thời gian thực hiện dự kiến -->\n              <div class=\"bg-[#fff9f3] border border-[#ffedd5] rounded-2xl p-6 flex flex-col md:flex-row gap-4 items-start shadow-sm\">\n                <div class=\"w-10 h-10 bg-[#ffedd5] text-brand-orange rounded-xl flex items-center justify-center text-lg flex-shrink-0\">\n                  <i class=\"fa-regular fa-file-lines\"></i>\n                </div>\n                <div class=\"space-y-2\">\n                  <h4 class=\"text-[15px] font-extrabold text-brand-orange\">\n                    Thời gian thực hiện dự kiến\n                  </h4>\n                  <p class=\"text-slate-600 text-[13px] leading-relaxed\">\n                    Thời gian chuẩn bị hồ sơ từ <strong class=\"text-slate-900 font-bold\">05 - 07 ngày</strong> và <strong class=\"text-slate-900 font-bold\">20 - 25 ngày</strong> làm việc với cơ quan nhà nước. Quý khách hàng sẽ nhận lại được <em class=\"text-indigo-950 font-medium\">\"Giấy chứng nhận đầu tư\"</em>, <em class=\"text-indigo-950 font-medium\">\"Giấy chứng nhận đăng ký doanh nghiệp\"</em>, <em class=\"text-indigo-950 font-medium\">\"Con dấu\"</em> và thông tin doanh nghiệp được công bố trên cổng thông tin quốc gia trong vòng <strong class=\"text-slate-900 font-bold\">25 - 30 ngày</strong> kể từ ngày cung cấp đủ hồ sơ.\n                  </p>\n                </div>\n              </div>\n\n            </section>\n          </div>', '', '', 'http://localhost:3000/uploads/1779524846691.jpg', 0, 'published', '2026-05-23', 'ho-tro-tu-van-xuc-tien-đau-tu-&-thanh-lap-fdi', '2026-05-23 08:27:46', '2026-05-23 08:27:46'),
(42, 'service', 'Dịch Vụ Tư Vấn Thành Lập Công Ty/ Doanh Nghiệp', 'FDI Company Establishment Service', 'FDI会社設立サービス', 'Chúng tôi cung cấp giải pháp toàn diện giúp các cá nhân, tổ chức trong nước khởi sự kinh doanh một cách hợp pháp, nhanh chóng và tối ưu nhất.', 'Consulting and establishment support for FDI companies in Vietnam', 'ベトナムにおけるFDI会社設立支援', '<div class=\"space-y-6\">\n            \n            <!-- Nút quay lại danh sách dịch vụ ở lề trên cùng -->\n            <button @click=\"handleMenuClick(\'home\')\" class=\"text-[#e2e8f0]/80 hover:text-white text-sm font-medium bg-transparent border-none cursor-pointer flex items-center gap-2 mb-2 transition-colors focus:outline-none\">\n              <i class=\"fa-solid fa-chevron-left text-xs\"></i> Quay lại danh sách dịch vụ\n            </button>\n\n            <!-- Tiêu đề lớn chứa Icon màu cam đúng ảnh b0a6ea.jpg -->\n            <div class=\"bg-[#1a4675] text-white rounded-t-[24px] p-6 flex items-center gap-4 shadow-xl\">\n              <div class=\"w-12 h-12 bg-white/10 rounded-xl flex items-center justify-center text-brand-orange flex-shrink-0\">\n                <i class=\"fa-solid fa-briefcase text-2xl\"></i>\n              </div>\n              <h1 class=\"text-lg md:text-[23px] font-extrabold tracking-tight leading-snug text-left\">\n                Dịch Vụ Tư Vấn Thành Lập Công Ty/ Doanh Nghiệp\n              </h1>\n            </div>\n\n            <!-- Khung nội dung trắng nằm bên dưới -->\n            <section class=\"bg-white rounded-b-[24px] p-8 md:p-10 shadow-xl text-slate-800 -mt-6 space-y-8\">\n              \n              <!-- Hộp cam chữ trắng chứa định vị giải pháp nổi bật chuẩn mẫu -->\n              <div class=\"bg-brand-orange text-white p-4 rounded-xl text-[14.5px] leading-relaxed font-semibold shadow-sm text-justify\">\n                Chúng tôi cung cấp giải pháp toàn diện giúp các cá nhân, tổ chức trong nước khởi sự kinh doanh một cách hợp pháp, nhanh chóng và tối ưu nhất.\n              </div>\n\n              <!-- Danh sách các bước từ 1 đến 5 (HTML Chay) -->\n              <div class=\"space-y-4\">\n                \n                <!-- Bước 1 -->\n                <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm flex items-start gap-4 transition hover:border-slate-200\">\n                  <div class=\"w-10 h-10 bg-[#eef2ff] text-indigo-600 font-bold rounded-full flex items-center justify-center flex-shrink-0 text-[14px]\">\n                    1\n                  </div>\n                  <p class=\"text-[#4b5563] text-[13.5px] md:text-[14px] leading-relaxed pt-1.5 text-left font-normal\">\n                    Hỗ trợ, tư vấn cách đặt tên công ty, tư vấn điều kiện của địa chỉ trụ sở công ty, tư vấn lựa chọn ngành nghề kinh doanh phù hợp với nhu cầu, tư vấn việc góp vốn, tỷ lệ góp vốn, quy định về góp vốn, tư vấn các loại thuế có liên quan...\n                  </p>\n                </div>\n\n                <!-- Bước 2 -->\n                <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm flex items-start gap-4 transition hover:border-slate-200\">\n                  <div class=\"w-10 h-10 bg-[#eef2ff] text-indigo-600 font-bold rounded-full flex items-center justify-center flex-shrink-0 text-[14px]\">\n                    2\n                  </div>\n                  <p class=\"text-[#4b5563] text-[13.5px] md:text-[14px] leading-relaxed pt-1.5 text-left font-normal\">\n                    Hỗ trợ, tư vấn về các quyền và nghĩa vụ của các chủ doanh nghiệp, chủ sở hữu, thành viên góp vốn, thành viên hợp danh, cổ đông góp vốn, cổ đông sáng lập, giám đốc công ty, chủ tịch công ty, ....\n                  </p>\n                </div>\n\n                <!-- Bước 3 -->\n                <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm flex items-start gap-4 transition hover:border-slate-200\">\n                  <div class=\"w-10 h-10 bg-[#eef2ff] text-indigo-600 font-bold rounded-full flex items-center justify-center flex-shrink-0 text-[14px]\">\n                    3\n                  </div>\n                  <p class=\"text-[#4b5563] text-[13.5px] md:text-[14px] leading-relaxed pt-1.5 text-left font-normal\">\n                    Hỗ trợ, tư vấn lựa chọn các loại hình công ty, doanh nghiệp để phù hợp với ngành nghề kinh doanh, quy mô sản xuất hoạt động kinh doanh.\n                  </p>\n                </div>\n\n                <!-- Bước 4 -->\n                <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm flex items-start gap-4 transition hover:border-slate-200\">\n                  <div class=\"w-10 h-10 bg-[#eef2ff] text-indigo-600 font-bold rounded-full flex items-center justify-center flex-shrink-0 text-[14px]\">\n                    4\n                  </div>\n                  <p class=\"text-[#4b5563] text-[13.5px] md:text-[14px] leading-relaxed pt-1.5 text-left font-normal\">\n                    Hỗ trợ thực hiện các thủ tục đăng ký thành lập công ty, thành lập doanh nghiệp.\n                  </p>\n                </div>\n\n                <!-- Bước 5 -->\n                <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm flex items-start gap-4 transition hover:border-slate-200\">\n                  <div class=\"w-10 h-10 bg-[#eef2ff] text-indigo-600 font-bold rounded-full flex items-center justify-center flex-shrink-0 text-[14px]\">\n                    5\n                  </div>\n                  <p class=\"text-[#4b5563] text-[13.5px] md:text-[14px] leading-relaxed pt-1.5 text-left font-normal\">\n                    Hỗ trợ các thủ tục cần thiết sau thành lập.\n                  </p>\n                </div>\n\n              </div>\n\n            </section>\n          </div>', '<div><h1>English Content</h1></div>', '<div><h1>日本語コンテンツ</h1></div>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=100&q=80&auto=format&fit=crop', 0, 'published', '2026-05-23', 'dich-vu-tu-van-thanh-lap-cong-ty/-doanh-nghiep', '2026-05-23 08:40:36', '2026-05-23 08:40:36'),
(43, 'service', 'Hỗ Trợ Thay Đổi Nội Dung Đăng Ký Kinh Doanh', 'FDI Company Establishment Service', 'FDI会社設立サービス', 'Tư vấn cho doanh nghiệp các vấn đề liên quan đến thay đổi nội dung đăng ký kinh doanh trong Luật doanh nghiệp 2020', 'Consulting and establishment support for FDI companies in Vietnam', 'ベトナムにおけるFDI会社設立支援', '<div  class=\"space-y-6\">\n            \n            <!-- Nút quay lại danh sách dịch vụ ở lề trên cùng -->\n            <button @click=\"handleMenuClick(\'home\')\" class=\"text-[#e2e8f0]/80 hover:text-white text-sm font-medium bg-transparent border-none cursor-pointer flex items-center gap-2 mb-2 transition-colors focus:outline-none\">\n              <i class=\"fa-solid fa-chevron-left text-xs\"></i> Quay lại danh sách dịch vụ\n            </button>\n\n            <!-- Tiêu đề lớn chứa Icon màu cam đúng ảnh b0af24.png -->\n            <div class=\"bg-[#1a4675] text-white rounded-t-[24px] p-6 flex items-center gap-4 shadow-xl\">\n              <div class=\"w-12 h-12 bg-white/10 rounded-xl flex items-center justify-center text-brand-orange flex-shrink-0\">\n                <i class=\"fa-regular fa-file-lines text-2xl\"></i>\n              </div>\n              <h1 class=\"text-lg md:text-[23px] font-extrabold tracking-tight leading-snug text-left\">\n                Hỗ Trợ Thay Đổi Nội Dung Đăng Ký Kinh Doanh\n              </h1>\n            </div>\n\n            <!-- Khung nội dung trắng nằm bên dưới -->\n            <section class=\"bg-white rounded-b-[24px] p-8 md:p-10 shadow-xl text-slate-800 -mt-6 space-y-6\">\n              \n              <!-- Dòng giới thiệu đầu tiên -->\n              <p class=\"text-slate-600 text-[14.5px] leading-relaxed text-left font-semibold\">\n                Chúng tôi sẽ hỗ trợ quý doanh nghiệp giải đáp các thắc mắc sau:\n              </p>\n\n              <!-- Hộp màu xám chứa danh sách 2 cột của Luật Doanh Nghiệp 2020 -->\n              <div class=\"bg-[#f8fafc] border border-slate-100 rounded-2xl p-6 shadow-sm space-y-4\">\n                <p class=\"text-indigo-950 font-bold text-[14px] leading-relaxed text-justify\">\n                  Tư vấn cho doanh nghiệp các vấn đề liên quan đến thay đổi nội dung đăng ký kinh doanh trong Luật doanh nghiệp 2020. Các nội dung tư vấn phụ thuộc vào yêu cầu của quý khách hàng bao gồm:\n                </p>\n\n                <!-- Lưới 2 cột căn chỉnh thẳng thớm, dấu chấm tròn cam nổi bật -->\n                <div class=\"grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-3.5 pt-2\">\n                  \n                  <!-- Cột trái -->\n                  <div class=\"space-y-3\">\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi tên công ty</span>\n                    </div>\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi số điện thoại, email, website</span>\n                    </div>\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi vốn điều lệ</span>\n                    </div>\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi các vấn đề liên quan khác</span>\n                    </div>\n                  </div>\n\n                  <!-- Cột phải -->\n                  <div class=\"space-y-3\">\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi trụ sở chính</span>\n                    </div>\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi ngành nghề kinh doanh</span>\n                    </div>\n                    <div class=\"flex items-center gap-3 text-slate-600 text-[13.5px]\">\n                      <span class=\"w-2 h-2 bg-brand-orange rounded-full flex-shrink-0\"></span>\n                      <span>Tư vấn thay đổi người đại diện pháp luật</span>\n                    </div>\n                  </div>\n\n                </div>\n              </div>\n\n              <!-- Đường kẻ phân cách ngang -->\n              <div class=\"border-t border-slate-100 my-6\"></div>\n\n              <!-- Khối Nội Dung Hỗ Trợ -->\n              <div class=\"space-y-4\">\n                <h3 class=\"text-indigo-950 font-extrabold text-[16px] text-left\">\n                  Nội dung hỗ trợ:\n                </h3>\n\n                <!-- Danh sách nội dung hỗ trợ căn lề trái thẳng, dấu bullet màu xanh/indigo -->\n                <div class=\"space-y-4\">\n                  <div class=\"flex items-start gap-3 text-slate-600 text-[13.5px] leading-relaxed\">\n                    <span class=\"w-2 h-2 bg-indigo-600 rounded-full flex-shrink-0 mt-2\"></span>\n                    <span class=\"text-left font-normal\">Hỗ trợ, tư vấn soạn thảo hồ sơ đăng ký thay đổi nội dung đăng ký kinh doanh phù hợp với yêu cầu của khách hàng;</span>\n                  </div>\n\n                  <div class=\"flex items-start gap-3 text-slate-600 text-[13.5px] leading-relaxed\">\n                    <span class=\"w-2 h-2 bg-indigo-600 rounded-full flex-shrink-0 mt-2\"></span>\n                    <span class=\"text-left font-normal\">Hỗ trợ đại diện cho khách hàng tiến hành thực hiện các thủ tục liên quan đến thay đổi giấy phép kinh doanh cho doanh nghiệp. Chúng tôi sẽ làm việc với cơ quan đăng ký doanh nghiệp, cơ quan thuế, và các cơ quan liên quan khác trong suốt quá trình thực hiện dịch vụ;</span>\n                  </div>\n\n                  <div class=\"flex items-start gap-3 text-slate-600 text-[13.5px] leading-relaxed\">\n                    <span class=\"w-2 h-2 bg-indigo-600 rounded-full flex-shrink-0 mt-2\"></span>\n                    <span class=\"text-left font-normal\">Hỗ trợ, tư vấn các thủ tục sau khi thay đổi đăng ký kinh doanh;</span>\n                  </div>\n\n                  <div class=\"flex items-start gap-3 text-slate-600 text-[13.5px] leading-relaxed\">\n                    <span class=\"w-2 h-2 bg-indigo-600 rounded-full flex-shrink-0 mt-2\"></span>\n                    <span class=\"text-left font-normal\">Tư vấn các thủ tục liên quan khác;</span>\n                  </div>\n                </div>\n              </div>', '<div><h1>English Content</h1></div>', '<div><h1>日本語コンテンツ</h1></div>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=100&q=80&auto=format&fit=crop', 0, 'published', '2026-05-23', 'ho-tro-thay-đoi-noi-dung-đang-ky-kinh-doanh', '2026-05-23 08:43:51', '2026-05-23 08:43:51'),
(44, 'service', 'Dịch Vụ Xin Visa Việt Nam Cho Người Nước Ngoài', 'FDI Company Establishment Service', 'FDI会社設立サービス', 'Thủ tục xin nhập cảnh cho người nước ngoài vào Việt Nam theo quy định hiện hành được LE VIET NAM xử lý nhanh chóng, chuyên nghiệp.', 'Consulting and establishment support for FDI companies in Vietnam', 'ベトナムにおけるFDI会社設立支援', '<div class=\"space-y-6\">\n            \n            <!-- Nút quay lại danh sách dịch vụ ở lề trên cùng -->\n            <button @click=\"handleMenuClick(\'home\')\" class=\"text-[#e2e8f0]/80 hover:text-white text-sm font-medium bg-transparent border-none cursor-pointer flex items-center gap-2 mb-2 transition-colors focus:outline-none font-sans\">\n              <i class=\"fa-solid fa-chevron-left text-xs\"></i> Quay lại danh sách dịch vụ\n            </button>\n\n            <!-- Tiêu đề lớn chứa Icon màu cam đúng ảnh b0b951.png -->\n            <div class=\"bg-[#1a4675] text-white rounded-t-[24px] p-6 flex items-center gap-4 shadow-xl\">\n              <div class=\"w-12 h-12 bg-white/10 rounded-full flex items-center justify-center text-brand-orange flex-shrink-0\">\n                <i class=\"fa-solid fa-earth-asia text-2xl\"></i>\n              </div>\n              <h1 class=\"text-lg md:text-[23px] font-extrabold tracking-tight leading-snug text-left font-sans\">\n                Dịch Vụ Xin Visa Việt Nam Cho Người Nước Ngoài\n              </h1>\n            </div>\n\n            <!-- Khung nội dung trắng nằm bên dưới -->\n            <section class=\"bg-white rounded-b-[24px] p-8 md:p-10 shadow-xl text-slate-800 -mt-6 space-y-6\">\n              \n              <!-- Hộp cam chứa slogan giới thiệu -->\n              <div class=\"bg-brand-orange text-white p-4 rounded-xl text-[14px] md:text-[14.5px] leading-relaxed font-semibold shadow-sm text-justify\">\n                Thủ tục xin nhập cảnh cho người nước ngoài vào Việt Nam theo quy định hiện hành được LE VIET NAM xử lý nhanh chóng, chuyên nghiệp.\n              </div>\n\n              <!-- Phần A: Đối tượng xin visa nhập cảnh -->\n              <div class=\"space-y-3 pt-2 text-left\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  A. Đối tượng xin visa nhập cảnh\n                </h3>\n                <p class=\"text-slate-600 text-[13.5px] md:text-[14px] leading-relaxed\">\n                  Tất cả công dân người nước ngoài đều được phép xuất nhập cảnh Việt Nam trừ một số trường hợp bị cấm/hạn chế. Các mục đích phổ biến: Chuyên gia, lao động, Nhà đầu tư, Thăm thân, Du lịch, Hội nghị...\n                </p>\n              </div>\n\n              <!-- Phần B: Cá nhân, Tổ chức được bảo lãnh -->\n              <div class=\"space-y-3 pt-2 text-left\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  B. Cá nhân, Tổ chức được bảo lãnh\n                </h3>\n                <ul class=\"list-none pl-1 space-y-2 text-slate-600 text-[13.5px] md:text-[14px]\">\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Các công ty, doanh nghiệp (TNHH, Cổ phần, Hợp danh, FDI).</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Chi nhánh, văn phòng đại diện.</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Tổ chức phi chính phủ, tổ chức quốc tế, hiệp hội.</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Cá nhân công dân Việt Nam hoặc người nước ngoài đang tạm trú/thường trú (bảo lãnh thân nhân).</span>\n                  </li>\n                </ul>\n              </div>\n\n              <!-- Phần C: Xin công văn nhập cảnh Online & Trực tiếp -->\n              <div class=\"space-y-4 pt-2 text-left\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  C. Xin công văn nhập cảnh Online & Trực tiếp\n                </h3>\n\n                <!-- Hộp màu xanh nhạt lưu ý quan trọng và quy trình -->\n                <div class=\"bg-[#f8fafc] border border-slate-100 rounded-2xl p-6 shadow-sm space-y-6\">\n                  \n                  <!-- Lưu ý quan trọng -->\n                  <div class=\"space-y-2.5\">\n                    <h4 class=\"text-indigo-950 font-bold text-[14.5px]\">\n                      Lưu ý quan trọng:\n                    </h4>\n                    <ul class=\"list-none pl-1 space-y-1.5 text-slate-600 text-[13.5px]\">\n                      <li class=\"flex items-start gap-2\">\n                        <span>-</span>\n                        <span>Hộ chiếu phải còn thời hạn tối thiểu <strong class=\"text-indigo-950 font-bold\">06 tháng.</strong></span>\n                      </li>\n                      <li class=\"flex items-start gap-2\">\n                        <span>-</span>\n                        <span>Nơi nhận visa có thể là: Sân bay quốc tế, cửa khẩu đường bộ, hoặc Đại sứ quán/Lãnh sự quán Việt Nam tại nước ngoài.</span>\n                      </li>\n                    </ul>\n                  </div>\n\n                  <!-- Quy trình nộp Online -->\n                  <div class=\"space-y-3 border-t border-slate-200/60 pt-4\">\n                    <h4 class=\"text-indigo-950 font-bold text-[14.5px]\">\n                      Quy trình nộp Online (Cổng dịch vụ công):\n                    </h4>\n                    <ol class=\"list-none pl-1 space-y-2.5 text-slate-600 text-[13.5px]\">\n                      <li class=\"flex gap-2.5 items-start\">\n                        <span class=\"font-semibold text-slate-700\">1.</span>\n                        <span>Đăng ký tài khoản điện tử cho doanh nghiệp.</span>\n                      </li>\n                      <li class=\"flex gap-2.5 items-start\">\n                        <span class=\"font-semibold text-slate-700\">2.</span>\n                        <span>Khai thông tin xin cấp công văn, tải hồ sơ và ký điện tử.</span>\n                      </li>\n                      <li class=\"flex gap-2.5 items-start\">\n                        <span class=\"font-semibold text-slate-700\">3.</span>\n                        <span>Bổ sung hồ sơ nếu có yêu cầu.</span>\n                      </li>\n                      <li class=\"flex gap-2.5 items-start\">\n                        <span class=\"font-semibold text-slate-700\">4.</span>\n                        <span>Nhận file công văn nhập cảnh sau 5 ngày làm việc.</span>\n                      </li>\n                    </ol>\n                  </div>\n\n                </div>\n              </div>\n\n              <!-- Dòng chú thích nghiêng dưới cùng chân trang -->\n              <p class=\"text-[#64748b] text-[12px] italic leading-relaxed text-left pt-2\">\n                Tại nơi nhận visa nhập cảnh, người nước ngoài cần xuất trình: Hộ chiếu gốc, Công văn nhập cảnh, Tờ khai NA1 có dán ảnh 4x6cm và nộp lệ phí visa theo quy định.\n              </p>', '<div><h1>English Content</h1></div>', '<div><h1>日本語コンテンツ</h1></div>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=100&q=80&auto=format&fit=crop', 0, 'published', '2026-05-23', 'dich-vu-xin-visa-viet-nam-cho-nguoi-nuoc-ngoai', '2026-05-23 08:46:46', '2026-05-23 08:53:29'),
(45, 'service', 'Dịch Vụ Thẻ Tạm Trú Cho Người Nước Ngoài', 'FDI Company Establishment Service', 'FDI会社設立サービス', 'Chúng tôi chuyên cung cấp dịch vụ xin cấp mới, gia hạn, cấp lại thẻ tạm trú cho người nước ngoài tại Hà Nội và TP Hồ Chí Minh.', 'Consulting and establishment support for FDI companies in Vietnam', 'ベトナムにおけるFDI会社設立支援', '<div class=\"space-y-6\">\n            \n            <!-- Nút quay lại danh sách dịch vụ ở lề trên cùng -->\n            <button @click=\"handleMenuClick(\'home\')\" class=\"text-[#e2e8f0]/80 hover:text-white text-sm font-medium bg-transparent border-none cursor-pointer flex items-center gap-2 mb-2 transition-colors focus:outline-none font-sans\">\n              <i class=\"fa-solid fa-chevron-left text-xs\"></i> Quay lại danh sách dịch vụ\n            </button>\n\n            <!-- Tiêu đề lớn chứa Icon đúng ảnh b10c9c.png -->\n            <div class=\"bg-[#1a4675] text-white rounded-t-[24px] p-6 flex items-center gap-4 shadow-xl\">\n              <div class=\"w-12 h-12 bg-white/10 rounded-xl flex items-center justify-center text-brand-orange flex-shrink-0\">\n                <i class=\"fa-regular fa-file-lines text-2xl\"></i>\n              </div>\n              <h1 class=\"text-lg md:text-[23px] font-extrabold tracking-tight leading-snug text-left font-sans\">\n                Dịch Vụ Thẻ Tạm Trú Cho Người Nước Ngoài\n              </h1>\n            </div>\n\n            <!-- Khung nội dung trắng nằm bên dưới -->\n            <section class=\"bg-white rounded-b-[24px] p-8 md:p-10 shadow-xl text-slate-800 -mt-6 space-y-6\">\n              \n              <!-- Slogan giới thiệu -->\n              <p class=\"text-slate-600 text-[14px] md:text-[14.5px] leading-relaxed text-left font-medium\">\n                Chúng tôi chuyên cung cấp dịch vụ xin cấp mới, gia hạn, cấp lại thẻ tạm trú cho người nước ngoài tại Hà Nội và TP Hồ Chí Minh.\n              </p>\n\n              <!-- A. Tư vấn hồ sơ (Khung bo góc, viền trái cam) -->\n              <div class=\"bg-[#f8fafc] border-l-4 border-orange-500 rounded-r-2xl p-6 shadow-sm space-y-3 text-left\">\n                <h3 class=\"text-[#1a365d] font-bold text-[16px]\">\n                  A. Tư vấn hồ sơ\n                </h3>\n                <ul class=\"list-none pl-1 space-y-2.5 text-slate-600 text-[13.5px] md:text-[14px]\">\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1\">•</span>\n                    <span>Tư vấn các điều kiện đầy đủ để người nước ngoài xin cấp thẻ (loại hộ chiếu, thời hạn...).</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1\">•</span>\n                    <span>Hỗ trợ chuẩn bị hồ sơ cá nhân và hồ sơ pháp lý doanh nghiệp/tổ chức bảo lãnh theo đúng quy định.</span>\n                  </li>\n                </ul>\n              </div>\n\n              <!-- B. Đại diện thực hiện thủ tục (Khung bo góc, viền trái tím/indigo) -->\n              <div class=\"bg-[#f8fafc] border-l-4 border-indigo-600 rounded-r-2xl p-6 shadow-sm space-y-3 text-left\">\n                <h3 class=\"text-[#1a365d] font-bold text-[16px]\">\n                  B. Đại diện thực hiện thủ tục\n                </h3>\n                <p class=\"text-slate-600 text-[13.5px] md:text-[14px] leading-relaxed font-medium\">\n                  Trong mọi trường hợp (doanh nghiệp bảo lãnh lao động/nhà đầu tư, cá nhân bảo lãnh vợ/chồng/bố mẹ...), chúng tôi đại diện theo ủy quyền để:\n                </p>\n                <ul class=\"list-none pl-1 space-y-2.5 text-slate-600 text-[13.5px] md:text-[14px] pt-1\">\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1\">•</span>\n                    <span>Nộp hồ sơ trực tiếp tại Cơ quan quản lý xuất nhập cảnh.</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1\">•</span>\n                    <span>Theo dõi, giải trình và nhận kết quả thẻ tạm trú giao tận tay khách hàng.</span>\n                  </li>\n                </ul>\n              </div>\n\n              <!-- C. Quy trình 3 bước đơn giản -->\n              <div class=\"space-y-4 pt-2 text-left\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  C. Quy trình 3 bước đơn giản\n                </h3>\n\n                <!-- Grid quy trình 3 cột -->\n                <div class=\"grid grid-cols-1 md:grid-cols-3 gap-5 pt-1\">\n                  \n                  <!-- Bước 1 -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm text-center space-y-3 flex flex-col justify-start items-center\">\n                    <div class=\"w-9 h-9 bg-orange-50 text-brand-orange font-bold rounded-full flex items-center justify-center text-sm shadow-inner\">\n                      1\n                    </div>\n                    <h4 class=\"text-[#1a365d] font-extrabold text-[14.5px]\">\n                      Liên hệ & Hướng dẫn\n                    </h4>\n                    <p class=\"text-slate-500 text-[12.5px] leading-relaxed font-normal\">\n                      Tư vấn và hướng dẫn chuẩn bị hồ sơ với thủ tục đơn giản nhất qua kênh online/trực tiếp.\n                    </p>\n                  </div>\n\n                  <!-- Bước 2 -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm text-center space-y-3 flex flex-col justify-start items-center\">\n                    <div class=\"w-9 h-9 bg-orange-50 text-brand-orange font-bold rounded-full flex items-center justify-center text-sm shadow-inner\">\n                      2\n                    </div>\n                    <h4 class=\"text-[#1a365d] font-extrabold text-[14.5px]\">\n                      Giao nhận & Nộp hồ sơ\n                    </h4>\n                    <p class=\"text-slate-500 text-[12.5px] leading-relaxed font-normal\">\n                      Nhận hồ sơ tại văn phòng, thực hiện thủ tục nộp theo ủy quyền tại cơ quan nhà nước.\n                    </p>\n                  </div>\n\n                  <!-- Bước 3 -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl p-5 shadow-sm text-center space-y-3 flex flex-col justify-start items-center\">\n                    <div class=\"w-9 h-9 bg-orange-50 text-brand-orange font-bold rounded-full flex items-center justify-center text-sm shadow-inner\">\n                      3\n                    </div>\n                    <h4 class=\"text-[#1a365d] font-extrabold text-[14.5px]\">\n                      Nhận kết quả\n                    </h4>\n                    <p class=\"text-slate-500 text-[12.5px] leading-relaxed font-normal\">\n                      Trả thẻ tạm trú trong <strong class=\"text-indigo-950 font-extrabold\">06 ngày</strong> (hoặc xử lý khẩn), thanh toán và xuất hóa đơn dịch vụ.\n                    </p>\n                  </div>\n\n                </div>\n              </div>\n', '<div><h1>English Content</h1></div>', '<div><h1>日本語コンテンツ</h1></div>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=100&q=80&auto=format&fit=crop', 0, 'published', '2026-05-23', 'dich-vu-the-tam-tru-cho-nguoi-nuoc-ngoai', '2026-05-23 08:49:05', '2026-05-23 08:49:05'),
(46, 'service', 'Giấy Phép Lao Động Cho Người Nước Ngoài (Work Permit)', 'FDI Company Establishment Service', 'FDI会社設立サービス', 'Cung cấp dịch vụ cấp mới, cấp lại, gia hạn giấy phép lao động ngắn hạn và dài hạn (lên tới 2 năm) cho người nước ngoài làm việc tại Việt Nam.', 'Consulting and establishment support for FDI companies in Vietnam', 'ベトナムにおけるFDI会社設立支援', '<div  class=\"space-y-6\">\n            \n            <!-- Nút quay lại danh sách dịch vụ ở lề trên cùng -->\n            <button @click=\"handleMenuClick(\'home\')\" class=\"text-[#e2e8f0]/80 hover:text-white text-sm font-medium bg-transparent border-none cursor-pointer flex items-center gap-2 mb-2 transition-colors focus:outline-none font-sans\">\n              <i class=\"fa-solid fa-chevron-left text-xs\"></i> Quay lại danh sách dịch vụ\n            </button>\n\n            <!-- Tiêu đề lớn chứa Icon đúng ảnh b113c1.png -->\n            <div class=\"bg-[#1a4675] text-white rounded-t-[24px] p-6 flex items-center gap-4 shadow-xl\">\n              <div class=\"w-12 h-12 bg-white/10 rounded-xl flex items-center justify-center text-brand-orange flex-shrink-0\">\n                <i class=\"fa-regular fa-file-lines text-2xl\"></i>\n              </div>\n              <h1 class=\"text-lg md:text-[23px] font-extrabold tracking-tight leading-snug text-left font-sans\">\n                Giấy Phép Lao Động Cho Người Nước Ngoài (Work Permit)\n              </h1>\n            </div>\n\n            <!-- Khung nội dung trắng nằm bên dưới -->\n            <section class=\"bg-white rounded-b-[24px] p-8 md:p-10 shadow-xl text-slate-800 -mt-6 space-y-6\">\n              \n              <!-- Slogan giới thiệu -->\n              <p class=\"text-slate-600 text-[14px] md:text-[14.5px] leading-relaxed text-left font-medium\">\n                Cung cấp dịch vụ cấp mới, cấp lại, gia hạn giấy phép lao động ngắn hạn và dài hạn (lên tới 2 năm) cho người nước ngoài làm việc tại Việt Nam.\n              </p>\n\n              <!-- A. Xin công văn chấp thuận sử dụng lao động -->\n              <div class=\"border-l-4 border-slate-200 pl-4 py-1 text-left space-y-2\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  A. Xin công văn chấp thuận sử dụng lao động\n                </h3>\n                <p class=\"text-slate-600 text-[13.5px] md:text-[14px] leading-relaxed\">\n                  Là điều kiện bắt buộc đầu tiên. Chúng tôi hỗ trợ giải thích quy định, chuẩn bị hồ sơ giải trình nhu cầu sử dụng lao động, và nộp hồ sơ online/trực tiếp tại Cơ quan quản lý lao động.\n                </p>\n              </div>\n\n              <!-- B. Cấp mới giấy phép lao động (Lần đầu) -->\n              <div class=\"text-left space-y-2 pt-2\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  B. Cấp mới giấy phép lao động (Lần đầu)\n                </h3>\n                <ul class=\"list-none pl-1 space-y-2 text-slate-600 text-[13.5px] md:text-[14px]\">\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Cho chức danh Nhà quản lý (Giám đốc, TGĐ, Trưởng VPĐD...).</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Cho Chuyên gia nước ngoài và Lao động kỹ thuật.</span>\n                  </li>\n                  <li class=\"flex items-start gap-2.5\">\n                    <span class=\"text-slate-900 mt-1.5\">•</span>\n                    <span>Thủ tục xin cấp Giấy miễn giấy phép lao động.</span>\n                  </li>\n                </ul>\n              </div>\n\n              <!-- C. Cấp lại giấy phép lao động -->\n              <div class=\"border-l-4 border-slate-200 pl-4 py-1 text-left space-y-2 pt-2\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  C. Cấp lại giấy phép lao động\n                </h3>\n                <p class=\"text-slate-600 text-[13.5px] md:text-[14px] leading-relaxed\">\n                  Áp dụng khi GPLĐ còn hạn nhưng bị mất, rách, hỏng, hoặc có sự thay đổi thông tin cá nhân (số hộ chiếu, địa điểm làm việc, trụ sở công ty...).\n                </p>\n              </div>\n\n              <!-- D. Gia hạn giấy phép lao động -->\n              <div class=\"border-l-4 border-slate-200 pl-4 py-1 text-left space-y-2 pt-2\">\n                <h3 class=\"text-brand-orange font-bold text-[16px]\">\n                  D. Gia hạn giấy phép lao động\n                </h3>\n                <p class=\"text-slate-600 text-[13.5px] md:text-[14px] leading-relaxed\">\n                  Phải thực hiện trước khi GPLĐ hết hạn tối thiểu <strong class=\"text-indigo-950 font-extrabold\">45 ngày</strong>. Nếu quá hạn sẽ phải làm thủ tục cấp mới từ đầu. Chúng tôi tư vấn chuẩn bị hồ sơ và thời điểm nộp hồ sơ an toàn nhất.\n                </p>\n              </div>\n\n              <!-- Hộp cam quy trình thực hiện trọn gói -->\n              <div class=\"bg-[#fff9f3] border border-[#ffedd5] rounded-2xl p-6 text-left shadow-sm space-y-4 pt-5\">\n                <h4 class=\"text-[15.5px] font-extrabold text-indigo-950\">\n                  Quy trình thực hiện trọn gói\n                </h4>\n                <div class=\"space-y-3 text-slate-600 text-[13px] md:text-[13.5px] leading-relaxed\">\n                  <div class=\"flex items-start gap-2\">\n                    <strong class=\"text-slate-900 flex-shrink-0\">Bước 1:</strong>\n                    <span>Luật sư tư vấn, giải đáp pháp lý và hướng dẫn danh mục hồ sơ cần chuẩn bị cho từng chức danh.</span>\n                  </div>\n                  <div class=\"flex items-start gap-2\">\n                    <strong class=\"text-slate-900 flex-shrink-0\">Bước 2:</strong>\n                    <span>Khách hàng chuẩn bị các giấy tờ gốc, chúng tôi soạn thảo toàn bộ hồ sơ trình ký.</span>\n                  </div>\n                  <div class=\"flex items-start gap-2\">\n                    <strong class=\"text-slate-900 flex-shrink-0\">Bước 3:</strong>\n                    <span>Nộp hồ sơ và trực tiếp giải trình với Cơ quan quản lý lao động theo ủy quyền.</span>\n                  </div>\n                  <div class=\"flex items-start gap-2\">\n                    <strong class=\"text-slate-900 flex-shrink-0\">Bước 4:</strong>\n                    <span>Nhận kết quả Giấy phép lao động, bàn giao cho khách hàng và xuất hóa đơn thanh toán.</span>\n                  </div>\n                </div>\n              </div>\n', '<div><h1>English Content</h1></div>', '<div><h1>日本語コンテンツ</h1></div>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=100&q=80&auto=format&fit=crop', 0, 'published', '2026-05-23', 'giay-phep-lao-đong-cho-nguoi-nuoc-ngoai-(work-permit)', '2026-05-23 08:52:02', '2026-05-23 08:52:02');
INSERT INTO `articles` (`id`, `cate`, `title_vi`, `title_en`, `title_jp`, `desc_vi`, `desc_en`, `desc_jp`, `content_vi`, `content_en`, `content_jp`, `thumbnail`, `views`, `status`, `publish_date`, `slug`, `created_at`, `updated_at`) VALUES
(47, 'home', 'Giới Thiệu', '', '', 'LE VIET NAM tự hào là đơn vị tư vấn chiến lược hàng đầu, chuyên cung cấp các giải pháp toàn diện về tư vấn xúc tiến đầu tư và hỗ trợ thành lập doanh nghiệp trong nước cũng như quốc tế (FDI).\n\nVới đội ngũ chuyên gia giàu kinh nghiệm, chúng tôi cam kết đồng hành cùng doanh nghiệp từ những bước đầu tiên, giải quyết mọi thủ tục pháp lý phức tạp và nâng cao năng lực nhân sự, giúp doanh nghiệp phát triển bền vững tại thị trường Việt Nam.', '', '', '<div class=\"bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-200\"><div class=\"p-8 md:p-10 text-gray-900 space-y-6\"><h2 class=\"text-2xl font-bold text-orange-600 mb-4 border-b pb-2\">Câu Chuyện Của Chúng Tôi</h2><p class=\"leading-relaxed\"><strong>LE VIET NAM</strong> được thành lập với tâm huyết trở thành cầu nối vững chắc, đưa các nhà đầu tư quốc tế đến với thị trường Việt Nam đầy tiềm năng, đồng thời hỗ trợ các doanh nghiệp trong nước xây dựng nền móng pháp lý vững chắc.</p><p class=\"leading-relaxed\">Chúng tôi hiểu rằng, rào cản về thủ tục hành chính, pháp lý và sự khác biệt văn hóa luôn là những thách thức lớn đối với doanh nghiệp. Với đội ngũ chuyên gia, luật sư và cố vấn giàu kinh nghiệm, LE VIET NAM cam kết mang đến những giải pháp tư vấn toàn diện, chính xác và hiệu quả nhất.</p><div class=\"grid md:grid-cols-2 gap-8 mt-8\"><div class=\"bg-slate-50 p-6 rounded-xl border border-gray-100\"><h3 class=\"text-xl font-bold text-[#1e1b4b] mb-3 flex items-center gap-2\"><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-globe text-orange-500\" aria-hidden=\"true\"><circle cx=\"12\" cy=\"12\" r=\"10\"></circle><path d=\"M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20\"></path><path d=\"M2 12h20\"></path></svg> Tầm Nhìn</h3><p class=\"text-gray-700\">Trở thành đơn vị tư vấn chiến lược và cung cấp dịch vụ pháp lý hàng đầu tại Việt Nam, là điểm đến đầu tiên mà các nhà đầu tư quốc tế nghĩ tới khi quyết định thâm nhập thị trường Việt Nam.</p></div><div class=\"bg-slate-50 p-6 rounded-xl border border-gray-100\"><h3 class=\"text-xl font-bold text-[#1e1b4b] mb-3 flex items-center gap-2\"><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-circle-check-big text-orange-500\" aria-hidden=\"true\"><path d=\"M21.801 10A10 10 0 1 1 17 3.335\"></path><path d=\"m9 11 3 3L22 4\"></path></svg> Sứ Mệnh</h3><p class=\"text-gray-700\">Đơn giản hóa mọi thủ tục pháp lý phức tạp, tối ưu hóa thời gian và chi phí cho khách hàng. Nâng tầm năng lực nhân sự Việt thông qua các chương trình đào tạo chuẩn quốc tế.</p></div></div><h2 class=\"text-2xl font-bold text-orange-600 mb-4 border-b pb-2 mt-10\">Giá Trị Cốt Lõi</h2><div class=\"grid grid-cols-1 sm:grid-cols-3 gap-6\"><div class=\"text-center p-4\"><div class=\"bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-orange-600 font-bold text-xl\">01</div><h4 class=\"font-bold text-indigo-900 mb-2\">Chuyên Nghiệp</h4><p class=\"text-sm text-gray-600\">Am hiểu luật pháp, xử lý hồ sơ nhanh chóng, chính xác.</p></div><div class=\"text-center p-4\"><div class=\"bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-orange-600 font-bold text-xl\">02</div><h4 class=\"font-bold text-indigo-900 mb-2\">Tận Tâm</h4><p class=\"text-sm text-gray-600\">Luôn đặt lợi ích của khách hàng lên hàng đầu, đồng hành trọn đời.</p></div><div class=\"text-center p-4\"><div class=\"bg-orange-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-orange-600 font-bold text-xl\">03</div><h4 class=\"font-bold text-indigo-900 mb-2\">Bảo Mật</h4><p class=\"text-sm text-gray-600\">Cam kết bảo mật tuyệt đối mọi thông tin của doanh nghiệp và đối tác.</p></div></div></div></div>\n', '', '', 'http://localhost:3000/uploads/1779464125563.jpg', 0, 'published', '2026-05-22', 'gioi-thieu', '2026-05-23 10:36:19', '2026-05-23 10:36:19'),
(54, 'news', 'Chính sách mới về cấp Work Permit cho chuyên gia nước ngoài 2024', NULL, NULL, 'Cập nhật những thay đổi quan trọng trong quy định cấp mới và gia hạn giấy phép lao động cho người nước ngoài tại Việt Nam...', NULL, NULL, '<p><strong>Theo quy định mới nhất của Ch&iacute;nh phủ...</strong></p>\n\n<p>Việc cấp giấy ph&eacute;p lao động cho chuy&ecirc;n gia, lao động kỹ thuật người nước ngo&agrave;i đ&atilde; c&oacute; một số thay đổi nhằm tạo điều kiện thuận lợi hơn cho doanh nghiệp.&nbsp;&nbsp;</p>\n', NULL, NULL, 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-23', 'chinh-sach-moi-ve-cap-work-permit-cho-chuyen-gia-nuoc-ngoai-2024', '2026-05-23 15:02:52', '2026-05-24 08:44:43'),
(55, 'news', 'Những lưu ý quan trọng khi thành lập công ty 100% vốn FDI', NULL, NULL, 'Quy trình, thủ tục và các điều kiện bắt buộc nhà đầu tư nước ngoài cần nắm rõ trước khi quyết định rót vốn vào thị trường Việt Nam.', NULL, NULL, '<p>Việt Nam tiếp tục là điểm đến hấp dẫn của dòng vốn FDI.</p>\r\n   <p>Nhà đầu tư cần kiểm tra kỹ ngành nghề kinh doanh có điều kiện hay không.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(56, 'news', 'Kỹ năng giao tiếp thấu cảm: Chìa khóa vàng trong quản trị nhân sự', NULL, NULL, 'Trong môi trường làm việc đa văn hóa và đa thế hệ, giao tiếp thấu cảm giúp gắn kết nhân viên và giảm thiểu xung đột hiệu quả.', NULL, NULL, '<p>Giao tiếp thấu cảm giúp xây dựng niềm tin và tăng hiệu quả làm việc.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1515162816999-a0c47dc192f7?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(57, 'news', 'Hướng dẫn chi tiết thủ tục cấp thẻ tạm trú cho nhà đầu tư FDI 2024', NULL, NULL, 'Để thuận lợi cho quá trình lưu trú và làm việc lâu dài tại Việt Nam, nhà đầu tư nước ngoài cần nắm rõ các điều kiện và quy trình xin cấp thẻ tạm trú.', NULL, NULL, '<p>Thẻ tạm trú giúp nhà đầu tư lưu trú dài hạn tại Việt Nam.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1569974498991-d3c12a504f95?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(58, 'news', 'Những thay đổi quan trọng của Luật Doanh nghiệp tác động đến nhà đầu tư', NULL, NULL, 'Nhiều quy định mới liên quan đến quản trị doanh nghiệp, con dấu, và thủ tục đăng ký kinh doanh được kỳ vọng tạo môi trường thông thoáng hơn.', NULL, NULL, '<p>Luật Doanh nghiệp mới tăng tính minh bạch và tự chủ cho doanh nghiệp.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1507679799987-c73779587ccf?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(59, 'news', 'Quy trình thành lập văn phòng đại diện thương nhân nước ngoài', NULL, NULL, 'Văn phòng đại diện là bước đệm an toàn để doanh nghiệp nước ngoài tìm hiểu và xúc tiến thương mại tại thị trường Việt Nam.', NULL, NULL, '<p>VPĐD phù hợp cho doanh nghiệp muốn nghiên cứu thị trường Việt Nam.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(60, 'news', 'Lưu ý khi xin visa điện tử (E-visa) cho chuyên gia vào Việt Nam', NULL, NULL, 'Visa điện tử mang lại sự tiện lợi lớn nhưng cũng có những hạn chế về thời gian lưu trú và số lần nhập cảnh.', NULL, NULL, '<p>E-visa giúp chuyên gia nước ngoài nhập cảnh nhanh hơn.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1436450412740-6b988f486c6b?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(61, 'news', 'Tầm quan trọng của văn hóa doanh nghiệp trong môi trường đa quốc gia', NULL, NULL, 'Sự thấu hiểu và tôn trọng đa dạng văn hóa là yếu tố cốt lõi giúp các công ty phát triển bền vững.', NULL, NULL, '<p>Văn hóa doanh nghiệp giúp tăng khả năng gắn kết nhân viên.</p>', NULL, NULL, 'https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-17', NULL, '2026-05-23 15:02:52', '2026-05-23 15:02:52'),
(62, 'news', 'Điều kiện để doanh nghiệp kinh doanh thương mại điện tử', NULL, NULL, 'Cập nhật các quy định pháp lý mới nhất đối với nhà đầu tư muốn thiết lập nền tảng bán lẻ trực tuyến tại Việt Nam.', NULL, NULL, '<p>TMĐT tại Việt Nam đang ph&aacute;t triển rất mạnh. t&ocirc;i l&agrave; vu&ecirc;n</p>\n', NULL, NULL, 'https://images.unsplash.com/photo-1556742049-0cfed4f6a45d?auto=format&fit=crop&q=80&w=800', 0, 'published', '2026-05-23', 'đieu-kien-đe-doanh-nghiep-kinh-doanh-thuong-mai-đien-tu', '2026-05-23 15:02:52', '2026-05-24 08:45:01'),
(68, 'training', 'Đào Tạo', '', '', 'Nâng Cao Kỹ Năng Giao Tiếp Trong Công Việc & Cuộc Sống\nHoàn tất chương trình, học viên sẽ được trang bị khả năng giao tiếp đa thế hệ, thấu cảm và ứng xử linh hoạt trên nền tảng số.', '', '', '<div class=\"space-y-6\">\n     \n            <!-- Tiêu đề lớn chứa Icon đúng ảnh b113c1.png/bdce27.png -->\n            <div class=\"bg-[#1a4675] text-white rounded-t-[24px] p-6 flex flex-col items-start gap-1.5 shadow-xl text-left\">\n              <h1 class=\"text-lg md:text-[23px] font-extrabold tracking-tight leading-snug font-sans\" style=\"color: #ffffff; margin-bottom:0px; margin-top: 10px;\">\n                Đào Tạo Kỹ Năng Giao Tiếp Tại Nơi Làm Việc\n              </h1>\n              <p class=\"text-xs md:text-sm text-slate-300 font-medium\">\n                Chương trình \"GIAO TIẾP THẤU CẢM & TẠO ẢNH HƯỞNG\"\n              </p>\n            </div>\n\n            <!-- Khung nội dung trắng nằm bên dưới -->\n            <section class=\"bg-white\" style=\"border-radius: 50px; \n    margin-top: 0px;\n\n\">\n              \n              <!-- Khối Cam Nâng Cao Kỹ Năng -->\n              <div class=\"bg-brand-orange text-white p-6 rounded-2xl shadow-sm text-left space-y-4\" style=\"    border-top-right-radius: 0px;     border-top-left-radius: 0px;\">\n                <div class=\"flex items-center gap-3\">\n                  <div class=\"w-10 h-10 bg-white/15 rounded-lg flex items-center justify-center\">\n                    <i class=\"fa-solid fa-graduation-cap text-xl\"></i>\n                  </div>\n                  <h2 class=\"text-lg font-extrabold leading-tight\" style=\"color: #ffffff\"> \n                    Nâng Cao Kỹ Năng Giao Tiếp Trong Công Việc & Cuộc Sống\n                  </h2>\n                </div>\n                <p class=\"text-[13.5px] leading-relaxed text-slate-100 font-normal\">\n                  Hoàn tất chương trình, học viên sẽ được trang bị khả năng giao tiếp đa thế hệ, thấu cảm và ứng xử linh hoạt trên nền tảng số.\n                </p>\n\n                <!-- Hai hộp chuyển đổi tư duy màu cam đậm -->\n                <div class=\"grid grid-cols-1 md:grid-cols-2 gap-4 pt-2\">\n                  <div class=\"bg-[#d95204] p-4 rounded-xl border border-white/10 space-y-1\">\n                    <span class=\"text-[11px] text-slate-200 block uppercase tracking-wider font-semibold\">Chuyển đổi từ</span>\n                    <p class=\"text-[13px] font-bold\">\"Giao tiếp thụ động\" → \"Chủ động kết nối\"</p>\n                  </div>\n                  <div class=\"bg-[#d95204] p-4 rounded-xl border border-white/10 space-y-1\">\n                    <span class=\"text-[11px] text-slate-200 block uppercase tracking-wider font-semibold\">Chuyển đổi từ</span>\n                    <p class=\"text-[13px] font-bold\">\"Thiếu tự chủ\" → \"Tự chủ\" ứng phó xung đột</p>\n                  </div>\n                </div>\n              </div>\n\n              <!-- Nội dung Chương Trình Đào Tạo -->\n              <div class=\"space-y-6 pt-5 p-5\">\n                <h3 class=\"text-center font-extrabold text-[#1a365d] text-[18px] tracking-wide uppercase\">\n                  Nội Dung Chương Trình Đào Tạo\n                </h3>\n\n                <!-- Danh sách 4 phần đào tạo -->\n                <div class=\"space-y-4\">\n                  \n                  <!-- Phần I -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl overflow-hidden shadow-sm flex flex-col md:flex-row transition hover:border-slate-200\">\n                    <div class=\"bg-[#1a224f] text-white p-6 md:w-[240px] flex-shrink-0 flex flex-col justify-center items-start text-left space-y-1\">\n                      <span class=\"text-brand-orange text-xs uppercase font-extrabold tracking-wider\">Phần I</span>\n                      <h4 class=\"font-extrabold text-[15px] leading-snug\" style=\"color: #ffffff\">\n                        Tổng Quan & Bối Cảnh Giao Tiếp Hiện Đại\n                      </h4>\n                    </div>\n                    <div class=\"p-6 flex-grow text-left\">\n                      <ul class=\"list-none pl-0 space-y-2.5 text-slate-600 text-[13.5px]\">\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Tầm quan trọng và đặc điểm giao tiếp trong doanh nghiệp hiện nay.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Tác động của chuyển đổi số, đa dạng văn hóa đến kỹ năng giao tiếp.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Quy trình xử lý thông tin trong giao tiếp.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Các rào cản, các yếu tố ảnh hưởng trong giao tiếp và kỹ năng xử lý hiệu quả.</span>\n                        </li>\n                      </ul>\n                    </div>\n                  </div>\n\n                  <!-- Phần II -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl overflow-hidden shadow-sm flex flex-col md:flex-row transition hover:border-slate-200\">\n                    <div class=\"bg-[#1a224f] text-white p-6 md:w-[240px] flex-shrink-0 flex flex-col justify-center items-start text-left space-y-1\">\n                      <span class=\"text-brand-orange text-xs uppercase font-extrabold tracking-wider\">Phần II</span>\n                      <h4 class=\"font-extrabold text-[15px] leading-snug\" style=\"color: #ffffff\">\n                        Giao Tiếp Hiệu Quả Đa Phương\n                      </h4>\n                    </div>\n                    <div class=\"p-6 flex-grow text-left\">\n                      <ul class=\"list-none pl-0 space-y-2.5 text-slate-600 text-[13.5px]\">\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Hiểu về đặc điểm và quan điểm của các thế hệ.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Xây dựng, kết nối và truyền cảm hứng đa thế hệ.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Văn hóa giao tiếp qua văn bản, email, điện thoại, trực tiếp và nền tảng số (Slack, Zoom...).</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Yếu tố chuyên nghiệp: phong thái, ngôn ngữ hình thể, và ngoại hình trong giao tiếp online.</span>\n                        </li>\n                      </ul>\n                    </div>\n                  </div>\n\n                  <!-- Phần III -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl overflow-hidden shadow-sm flex flex-col md:flex-row transition hover:border-slate-200\">\n                    <div class=\"bg-[#1a224f] text-white p-6 md:w-[240px] flex-shrink-0 flex flex-col justify-center items-start text-left space-y-1\">\n                      <span class=\"text-brand-orange text-xs uppercase font-extrabold tracking-wider\">Phần III</span>\n                      <h4 class=\"font-extrabold text-[15px] leading-snug\" style=\"color: #ffffff\">\n                        Nghệ Thuật Lắng Nghe Và Ứng Xử Hiệu Quả\n                      </h4>\n                    </div>\n                    <div class=\"p-6 flex-grow text-left\">\n                      <ul class=\"list-none pl-0 space-y-2.5 text-slate-600 text-[13.5px]\">\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Nghệ thuật lắng nghe chủ động và phản hồi tích cực.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Phương pháp đặt câu hỏi và / hoặc trả lời trong nghệ thuật giao tiếp.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Những lưu ý quan trọng trong giao tiếp nơi công sở.</span>\n                        </li>\n                      </ul>\n                    </div>\n                  </div>\n\n                  <!-- Phần IV -->\n                  <div class=\"bg-white border border-slate-100 rounded-2xl overflow-hidden shadow-sm flex flex-col md:flex-row transition hover:border-slate-200\">\n                    <div class=\"bg-[#1a224f] text-white p-6 md:w-[240px] flex-shrink-0 flex flex-col justify-center items-start text-left space-y-1\">\n                      <span class=\"text-brand-orange text-xs uppercase font-extrabold tracking-wider\">Phần IV</span>\n                      <h4 class=\"font-extrabold text-[15px] leading-snug\" style=\"color: #ffffff\">\n                        Giao Tiếp Thấu Cảm & Mô Hình Quốc Tế\n                      </h4>\n                    </div>\n                    <div class=\"p-6 flex-grow text-left\">\n                      <ul class=\"list-none pl-0 space-y-2.5 text-slate-600 text-[13.5px]\">\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Giao tiếp thấu cảm trong môi trường làm việc hiện đại.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Làm sao để thấu cảm nhưng không thỏa hiệp.</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Giới thiệu các mô hình giao tiếp hiệu quả: DITTO, Giao tiếp bất bạo động (NVC), 7Cs of Communication...</span>\n                        </li>\n                        <li class=\"flex items-start gap-2.5\">\n                          <span class=\"text-slate-900\">•</span>\n                          <span>Cách thức phản hồi, góp ý và quản trị xung đột.</span>\n                        </li>\n                      </ul>\n                    </div>\n                  </div>\n\n                </div>\n              </div>\n\n            </section>\n          </div>', '', '', '', 0, 'published', '2026-05-23', 'dao-tao', '2026-05-23 16:39:56', '2026-05-24 09:00:03');

